import { AppError } from '@/domain/exceptions/app-error';

/**
 * Unified Status Transition Validator
 * Enforces business rules for moving between student statuses.
 */
export class StatusTransitionHelper {
  static validate(student: any, nextStatus: string) {
    if (!nextStatus) return true;

    // Flatten data for easier check
    const healthCheck = student.health_check || {};
    const progressFlags = student.progress_flags || {};
    const courseId = student.course_id || student.latest_enrollment?.course_id;

    switch (nextStatus) {
      case 'Đã KSK':
        if (healthCheck.status !== 'Đủ điều kiện') {
          let msg = `Chưa đạt yêu cầu khám sức khỏe. Trạng thái hiện tại: "${healthCheck.status || 'Chưa khám'}".`;
          if (healthCheck.status === 'Không đủ điều kiện' && healthCheck.note) {
            msg += ` Lý do ghi chú: ${healthCheck.note}`;
          } else if (healthCheck.status === 'Chờ khám' || !healthCheck.status) {
            msg += ' Vui lòng cập nhật trạng thái "Đủ điều kiện" để tiếp tục.';
          }
          throw new AppError(msg, 400);
        }
        break;

      case 'Chờ xếp khóa':
        // Optional: Could require 'Đã KSK' first?
        break;

      case 'Đã vào khóa':
        if (!courseId) {
          throw new AppError('Học viên chưa được gán vào khóa học nào. Vui lòng xếp lớp trước.', 400);
        }
        break;

      case 'Đang thi':
        if (!progressFlags.graduation_eligible) {
          const missing = [];
          if (!progressFlags.theory_completed) missing.push('Lý thuyết');
          if (!progressFlags.sand_yard_completed) missing.push('Sa hình');
          if (!progressFlags.simulation_completed) missing.push('Mô phỏng');
          if (!progressFlags.dat_completed) missing.push('Đủ km DAT');
          if (!progressFlags.cabin_completed) missing.push('Cabin');

          let msg = 'Chưa đủ điều kiện thi tốt nghiệp.';
          if (missing.length > 0) {
            msg += ` Hạng mục còn thiếu: ${missing.join(', ')}.`;
          } else {
            msg += ' Vui lòng kiểm tra lại tổng kết điều kiện thi.';
          }
          throw new AppError(msg, 400);
        }
        break;

      case 'Đã đậu':
      case 'Thi lại':
        // These are usually set by the Exam result entry system.
        // If set manually, we might want to ensure they were 'Đang thi'.
        if (student.status_detail !== 'Đang thi') {
          // throw new AppError('Chỉ có thể nhập kết quả cho học viên đang trong trạng thái thi.', 400);
        }
        break;

      default:
        break;
    }

    return true;
  }
}

import { z } from 'zod';

export const registerSchema = z.object({
  body: z.object({
    username: z.string().trim().toLowerCase().min(3),
    password: z.string().min(6),
    first_name: z.string().trim().min(1),
    last_name: z.string().trim().min(1),
    email: z.string().trim().toLowerCase().email(),
    phone: z.string().trim().min(10),
    role: z.enum(['admin', 'staff', 'teacher', 'student']).default('student'),
    address: z.string().trim().default('N/A'),
    identity_card: z.string().trim().default('N/A'),
  }),
});

export const loginSchema = z.object({
  body: z.object({
    username: z.string().trim().toLowerCase(),
    password: z.string(),
  }),
});

export const changePasswordSchema = z.object({
  body: z
    .object({
      old_password: z.string().min(1),
      new_password: z.string().min(6),
      confirm_password: z.string().min(6),
    })
    .refine((data) => data.new_password === data.confirm_password, {
      message: 'Confirm password must match new password',
      path: ['confirm_password'],
    }),
});

